INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(14, 15, 1, '<p>Perhatikan pernyataan berikut ini:<br />(1) Dapat menghentikan konflik sementara<br />(2) Mengatasi masalah secara permanen<br />(3) Dapat dilakukan sesuai dengan kemampuan kita<br />(4) Bermanfaat bagi sebagian orang<br />(5) Mampu menginspirasi orang lain<br />Dari pernyataan tersebut, yang bukan merupakan pernyataan untuk menentukan solusi yang baik ditunjukan pada ide kreatif dengan nomor ...</p>', 1, '<p>(1), (2)</p>', '<p>(2), (3)</p>', '<p>(3), (4)</p>', '<p>(4), (5)</p>', '<p>(1), (4)</p>', 'E', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(15, 9, 40, '<p>Berikut ini yang bukan kewajiban istri terhadap suami dalam suatu pernikahan adalah .....</p>', 1, '<p>Memelihara dan mendidik anaknya</p>', '<p>Menghormati suami</p>', '<p>Menjaga kehormatan</p>', '<p>Memberi nafkah</p>', '<p>Patuh kepada suami</p>', 'A', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(16, 9, 39, '<p>Salah satu perbuatan halal tetapi dibenci oleh SWT adalah.......</p>', 1, '<p>Talak</p>', '<p>Rujuk</p>', '<p>Wakaf</p>', '<p>Idah</p>', '<p>Aqiqah</p>', 'A', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(17, 9, 38, '<p>Berikut yang bukan merupakan rukun pernikahan adalah .....</p>', 1, '<p>Calon istri</p>', '<p>Calon suami</p>', '<p>Saksi</p>', '<p>Teman dekat</p>', '<p>Wali</p>', 'D', '', '', '', '', '', '', ''),
(18, 9, 37, '<p>Seseorang yang tidak boleh atau haram dinikahi disebut ......</p>', 1, '<p>Muhsin</p>', '<p>Mahram</p>', '<p>Muallim</p>', '<p>Muzakki</p>', '<p>Muhrim</p>', 'B', '', '', '', '', '', '', ''),
(19, 9, 36, '<p>Seorang perempuan yang diceraikan atau ditinggal mati oleh suaminya memiliki masa tunggu untuk menikah lagi yang disebut .....</p>', 1, '<p>Talaq</p>', '<p>Rujuk</p>', '<p>Idah</p>', '<p>Khuluk</p>', '<p>Walimah</p>', 'C', '', '', '', '', '', '', ''),
(20, 9, 35, '<p>Hukum menikah bagi orang yang dikhawatirkan akan teledor dalam menunaikan kewajibanya setelah menikah adalah .....</p>', 1, '<p>Mubah</p>', '<p>Makruh</p>', '<p>Sunnah</p>', '<p>Haram</p>', '<p>Wajib</p>', 'B', '', '', '', '', '', '', ''),
(21, 15, 2, '<p>Perhatikan symbol bagan alir berikut ini :</p>\r\n<table style=\"border-collapse: collapse; width: 100%;\" border=\"1\">\r\n<tbody>\r\n<tr style=\"height: 67px;\">\r\n<td style=\"width: 19.9271%; height: 67px; text-align: center;\"><img src=\"data:image/png;base64,\" alt=\"\" /></td>\r\n<td style=\"width: 19.9271%; height: 67px; text-align: center;\"><img src=\"data:image/png;base64,\" alt=\"\" /></td>\r\n<td style=\"width: 20.0486%; height: 67px; text-align: center;\"><img src=\"data:image/png;base64,\" alt=\"\" /></td>\r\n<td style=\"width: 19.9271%; height: 67px; text-align: center;\"><img src=\"data:image/png;base64,\" alt=\"\" /></td>\r\n<td style=\"width: 20.0486%; height: 67px; text-align: center;\"><img src=\"data:image/png;base64,\" alt=\"\" /></td>\r\n</tr>\r\n<tr style=\"height: 38px;\">\r\n<td style=\"width: 19.9271%; height: 38px; text-align: center;\" width=\"119\">\r\n<p><strong>(1)</strong></p>\r\n</td>\r\n<td style=\"width: 19.9271%; height: 38px; text-align: center;\" width=\"115\">\r\n<p><strong>(2)</strong></p>\r\n</td>\r\n<td style=\"width: 20.0486%; height: 38px; text-align: center;\" width=\"115\">\r\n<p><strong>(3)</strong></p>\r\n</td>\r\n<td style=\"width: 19.9271%; height: 38px; text-align: center;\" width=\"115\">\r\n<p><strong>(4)</strong></p>\r\n</td>\r\n<td style=\"width: 20.0486%; height: 38px; text-align: center;\" width=\"113\">\r\n<p><strong>(5)</strong></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Dari symbol bagan alir diatas, simbol berfungsi sebagai untuk mengawali proses dan penentu keputusan ditunjukan pada nomor?</p>', 1, '<p>(1), (2)</p>', '<p>(2), (3)</p>', '<p>(3), (4)</p>', '<p>(1), (3)</p>', '<p>(5), (1)</p>', 'D', '', '', '', '', '', '', ''),
(22, 15, 3, '<p>Perhatikan gambar berikut :</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/jpeg;base64,\" alt=\"\" width=\"397\" height=\"467\" /></p>\r\n<p>Bentuk flowchart yang yang menggambarkan sebuah data terletak pada nomor&hellip;.</p>', 1, '<p>1 dan 3</p>', '<p>3 dan 4</p>', '<p>2 dan 3</p>', '<p>4 dan 5</p>', '<p>1 dan 4</p>', 'E', '', '', '', '', '', '', ''),
(23, 15, 4, '<p>Tika mendapat tugas untuk mencari suatu dokumen dengan menggunakan mesin pencari google.com. Sintaks yang tepat yang harus digunakan oleh Tika adalah menggunakan&hellip;</p>', 1, '<p>Allinurl</p>', '<p>Inurl</p>', '<p>Filetype</p>', '<p>Site</p>', '<p>Intitle</p>', 'C', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(24, 15, 5, '<p>Apakah maksud dari kata kunci pencarian berikut ini?</p>\r\n<p>Site:&nbsp;<strong>www.smkalkyai.sch.id</strong></p>', 1, '<p>mencari materi atau modul di URL tersebut dalam bentuk power point</p>', '<p>menampilkan seluruh situs web yang berasal dari Indonesia yang terkait dengan URL tersebut</p>', '<p>mencari gambar pada URL tersebut</p>', '<p>mencari halaman pada URL tersebut</p>', '<p>mencari deskripsi pada URL tersebut</p>', 'B', '', '', '', '', '', '', ''),
(25, 15, 6, '<p>Deni membuat sebuah dokumen melalui MS.Word dengan ukuran kertas A4, jumlah halaman dokumen tersebut sejumlah 10 halaman. Apabila Deni ingin memberikan nomor halaman dengan posisi penomoran berada dibagian atas pada setiap lembarnya, langkah tepat yang harus dilakukan Deni adalah...</p>', 1, '<p>Pilih tab Insert &rarr; Page Number &rarr; Top of Page</p>', '<p>Pilih tab Insert &rarr; Page Number &rarr; Bottom of Page</p>', '<p>Pilih tab Insert &rarr; Page Number &rarr; Page Margin</p>', '<p>Pilih tab Insert &rarr; Page Number &rarr; Current Position</p>', '<p>Pilih tab Insert &rarr; Page Number &rarr; Format Page Number</p>', 'A', '', '', '', '', '', '', ''),
(26, 15, 7, '<p>Ilham merupakan anak yang masih terbilang kecil. Akan tetapi, meskipun masih berusia sangat kcil, Ilham memiliki keinginan kuat untuk bisa membantu orang tuanya. Ilham sangat mengerti keadaan orang tuanya saat ini. Dimana ibunya hanya berjualan makanan ringan dan ayahnya berjualan kayu bakar di pasar.</p>\r\n<p>Melihat kenyataan seperti itu, maka ilham memiliki keinginan kuat untuk bisa membantuk kedua orang tuanya. Meskipun ibunya sudah melarangnya, namun ia tetap melakukannya. Setiap pulang sekolah Ilham pergi ke hutan untuk mencari kayu bakar. Sore harinya dibwa pulang. Hampir ia tidak memiliki kesempatan untuk bisa bermain bersama dengan teman-temanya.</p>\r\n<p>Paragraf di atas merupakan jenis paragraf...</p>', 1, '<p>deskripsi</p>', '<p>persuasi</p>', '<p>narasi</p>', '<p>eksposisi</p>', '<p>argumentasi</p>', 'C', '', '', '', '', '', '', ''),
(27, 15, 8, '<p>Perhatikan teks berikut</p>\r\n<p><span style=\"font-size: 24pt;\"><strong>SIMULASI DAN<span style=\"font-size: 18pt;\"><sup>KOMUNIKASI DIGITAL</sup></span></strong></span></p>\r\n<p>Untuk membuat teks seperti diatas, maka langkah-langkah yang tepat adalah...</p>', 1, '<p>Klik menu Home &rarr; Strikethrough</p>', '<p>Klik menu Home &rarr; Decrease Font Size</p>', '<p>Klik menu Home &rarr; Subscript</p>', '<p>Klik menu Home &rarr; Superscript</p>', '<p>Klik menu Home &rarr; Decrease Font Size</p>', 'D', '', '', '', '', '', '', ''),
(28, 15, 9, '<p>Dita telah membuat proposal rencana kegiatan OSIS. Setelah dicek kembali, ternyata font size yang digunakan terlalu besar, untuk bisa menurunkan satu tingkat font size dari sebelumnya, maka Langkah tepat yang dilakukan Dita adalah...</p>', 1, '<p>CTRL + Shift + /</p>', '<p>CTRL + Shift + &lt;</p>', '<p>CTRL + Shift + &gt;</p>', '<p>CTRL + Shift +?</p>', '<p>CTRL + Shift + \\</p>', 'B', '', '', '', '', '', '', ''),
(29, 15, 10, '<p>Pak Yanuar memiliki sebuah modul yang berisi sejumlah 100 halaman. Misalnya Pak Yanuar akan mencari kata Simulasi Digital Digital pada seluruh halaman, maka langkah yang tepat adalah dengan cara...</p>', 1, '<p>Pada tab Home, klik Go To / (CTRL+G) dikelompok Editing</p>', '<p>Pada tab Home, klik Find (CTRL+F) dikelompok Editing</p>', '<p>Mencari satu persatu setiap halaman</p>', '<p>Pada tab Home, klik Style</p>', '<p>Pada tab Home, klik Select</p>', 'B', '', '', '', '', '', '', ''),
(30, 9, 34, '<p>Apabila seseorang belum pantas untuk menikah, belum perbekalan belum ada, maka hukum nikah baginya adalah &hellip;.</p>', 1, '<p>Haram</p>', '<p>Wajib</p>', '<p>Mubah</p>', '<p>Makruh</p>', '<p>Sunnah</p>', 'D', '', '', '', '', '', '', ''),
(31, 9, 33, '<p>Nikah mut&rsquo;ah adalah &hellip;.</p>', 1, '<p>Perkawinan untuk masa selamanya</p>', '<p>Perkawinan sampai tua</p>', '<p>Perkawinan sampai mati</p>', '<p>Perkawinan untuk masa yang ditentukan (kawin kontrak)</p>', '<p>Pernikajan yang saling mencintai</p>', 'D', '', '', '', '', '', '', ''),
(32, 9, 32, '<p>Menantu tidak boleh dinikahi karena &hellip;.</p>', 1, '<p>Ada hubungan perkawinan</p>', '<p>Ada hubungan susuan</p>', '<p>Hubungan darah</p>', '<p>Ada hubungan perteman</p>', '<p>Ada hubungan persaudaraan&nbsp;</p>', 'A', '', '', '', '', '', '', ''),
(33, 15, 11, '<p>Perhatikan table berikut :</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/tiff;base64,\" alt=\"\" /><img class=\"img-responsive\" src=\"data:image/jpeg;base64,\" alt=\"\" width=\"596\" height=\"266\" /></p>\r\n<p>Untuk memiringkan posisi text pada kata &ldquo;<strong>TOTAL</strong>&rdquo; dilakukan dengan cara&hellip;.</p>', 1, '<p>klik cell yang dimaksud &ndash; klik tab home &ndash; group ribbon alligment &ndash; align text right</p>', '<p>klik cell yang dimaksud &ndash; klik tab home &ndash; group ribbon alligment &ndash; orientation</p>', '<p>klik cell yang dimaksud &ndash; klik tab home &ndash; group ribbon alligment &ndash; wrap text</p>', '<p>klik cell yang dimaksud &ndash; klik tab home &ndash; group ribbon alligment &ndash; decrease indent</p>', '<p>klik cell yang dimaksud &ndash; klik tab home &ndash; group ribbon alligment &ndash; increase indent Select</p>', 'B', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(34, 15, 12, '<p>Perhatikan tabel berikut :</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/jpeg;base64,\" alt=\"\" width=\"843\" height=\"407\" /></p>\r\n<p>Kolom Harga Total berasal dari kolom Harga Satuan dikalikan dengan Discount.</p>\r\n<p>Maka, penulisan rumus yang benar adalah</p>', 1, '<p>=IF(B3=101;7,5%*E3;IF(B3=102;10%*E3;5%*E3))</p>', '<p>=IF(B3=101,5%*E3,IF(B3=102,7.5%*E3,10%*E3))</p>', '<p>=IF(B3=101;10%*E3;IF(B3=102;5%*E3;7,5%*E3))</p>', '<p>=IF(B3=101,10%*E3,IF(B3=102,7.5%*E3,5%*E3))</p>', '<p>=IF(B3=101,5%*E3,IF(B3=102,10%*E3,7.5%*E3))</p>', 'C', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(35, 15, 13, '<p>Perhatikan table berikut :</p>\r\n<p>&nbsp;</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/jpeg;base64,\" alt=\"\" width=\"414\" height=\"183\" /></p>\r\n<p>Berdasarkan data pada gambar diatas, untuk membuat Grafik dengan bentuk garis pada Ms. Excel maka langkah-langkah yang harus dilakukan adalah&hellip;</p>', 1, '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Column</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Bar Chart</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Pie</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Line Chart</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Scatter</p>', 'D', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(36, 15, 14, '<p>Perhatikan table berikut :</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/jpeg;base64,\" alt=\"\" width=\"843\" height=\"407\" /></p>\r\n<p>Penulisan rumus yang benar pada cell C3 kolom nama barang adalah</p>', 1, '<p>=VLOOKUP(b3;a13:c15;1)</p>', '<p>=HLOOKUP(b3;a13:c15;2)</p>', '<p>=HLOOKUP(b3;a13:c15;1)</p>', '<p>=VLOOKUP(b3;a13:c15;3)</p>', '<p>=VLOOKUP(b3;a13:c15;2)</p>', 'E', '', '', '', '', '', '', '');
