(37, 15, 15, '<p>Perhatikan langkah-langkah berikut :</p>\r\n<p>(1) Pilih No Border</p>\r\n<p>(2) Blok cell atau range-nya</p>\r\n<p>(3) Pilih All Border</p>\r\n<p>(4) Klik menu Home dan Pada group Font, klik Border</p>\r\n<p>(5) Pilih Bottom Border</p>\r\n<p>(6) Pilih Top Border</p>\r\n<p>(7) Pilih Left Border</p>\r\n<p>Urutan langkah-lankah yang benar untuk menghilangkah border adalah&hellip;</p>', 1, '<p>(2), (4), (7)</p>', '<p>(2), (4), (6)</p>', '<p>(2), (4), (1)</p>', '<p>(2), (4), (3)</p>', '<p>(2), (4), (5)</p>', 'C', '', '', '', '', '', '', '');
