(38, 15, 16, '<p>Perhatikan data berikut :</p>\r\n<table style=\"border-collapse: collapse; width: 100%;\" border=\"1\">\r\n<tbody>\r\n<tr>\r\n<td style=\"text-align: center; width: 10.888%;\" width=\"107\">\r\n<p><strong>No</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 19.2569%;\" width=\"107\">\r\n<p><strong>Kelas</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.3782%;\" width=\"67\">\r\n<p><strong>S</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.4076%;\" width=\"64\">\r\n<p><strong>I</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 13.4872%;\" width=\"78\">\r\n<p><strong>A</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 21.6353%;\" width=\"163\">\r\n<p><strong>JUMLAH</strong></p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"text-align: center; width: 10.888%;\" width=\"107\">\r\n<p><strong>1</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 19.2569%;\" width=\"107\">\r\n<p>K-1</p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.3782%;\" width=\"67\">\r\n<p>7</p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.4076%;\" width=\"64\">\r\n<p>3</p>\r\n</td>\r\n<td style=\"text-align: center; width: 13.4872%;\" width=\"78\">\r\n<p>3</p>\r\n</td>\r\n<td style=\"text-align: center; width: 21.6353%;\" width=\"163\">\r\n<p>13</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"text-align: center; width: 10.888%;\" width=\"107\">\r\n<p><strong>2</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 19.2569%;\" width=\"107\">\r\n<p>K-2</p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.3782%;\" width=\"67\">\r\n<p>5</p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.4076%;\" width=\"64\">\r\n<p>4</p>\r\n</td>\r\n<td style=\"text-align: center; width: 13.4872%;\" width=\"78\">\r\n<p>5</p>\r\n</td>\r\n<td style=\"text-align: center; width: 21.6353%;\" width=\"163\">\r\n<p>14</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"text-align: center; width: 10.888%;\" width=\"107\">\r\n<p><strong>3</strong></p>\r\n</td>\r\n<td style=\"text-align: center; width: 19.2569%;\" width=\"107\">\r\n<p>K-3</p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.3782%;\" width=\"67\">\r\n<p>2</p>\r\n</td>\r\n<td style=\"text-align: center; width: 14.4076%;\" width=\"64\">\r\n<p>1</p>\r\n</td>\r\n<td style=\"text-align: center; width: 13.4872%;\" width=\"78\">\r\n<p>2</p>\r\n</td>\r\n<td style=\"text-align: center; width: 21.6353%;\" width=\"163\">\r\n<p>5</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Jika data diatas akan dibuat grafik dalam bentuk lingkaran maka langkah yang tepat adalah....</p>', 1, '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Pie</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Bar Chart</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Column</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Line Chart</p>', '<p>Pilih sel yang akan dibuat grafiknya, Klik tab Insert, klik Chart dan pilih jenis Scatter</p>', 'A', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(39, 15, 17, '<p>Perhatikan slide presentasi berikut :</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/jpeg;base64,\" alt=\"\" width=\"850\" height=\"495\" /></p>\r\n<p>Yang bukan merupakan Unsur logical pada slide ditunjukan pada nomor&hellip;.</p>', 1, '<p>5-1</p>', '<p>1-2</p>', '<p>3-4</p>', '<p>4-5</p>', '<p>2-3</p>', 'A', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(40, 15, 18, '<p>Andi akan telah membuat sebuah file presentasi. Apabila Andi akan menggandakan slide tertentu, maka langkah apa yang harus Andi dilakukan?</p>', 1, '<p>klik kanan pada slide &ndash; kemudian pilih reset slide</p>', '<p>klik kanan pada slide &ndash; kemudian pilih publish slide</p>', '<p>klik kanan pada slide &ndash; kemudian pilih add section</p>', '<p>klik kanan pada slide &ndash; kemudian pilih duplicate slide</p>', '<p>klik kanan pada slide &ndash; kemudian pilih layout</p>', 'D', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(41, 15, 19, '<p>Perhatikan pernyataan langkah-langkah berikut :</p>\r\n<p>(1) Klik file</p>\r\n<p>(2) Pada save as type pilih .jpg</p>\r\n<p>(3) Klik save</p>\r\n<p>(4) Klik save as</p>\r\n<p>(5) Tentukan nama file &ldquo;Susi File&rdquo;</p>\r\n<p>Jika Susi akan menyimpan file presentasi dengan type .jpg dan memberi nama file &ldquo;Susi File&rdquo; maka langkah-langkah yang tepat adalah&hellip;</p>', 1, '<p>(1), (4), (3), (2), (5)</p>', '<p>(1), (4), (2), (5), (3)</p>', '<p>(1), (4), (5), (2), (3)</p>', '<p>(1), (4), (2), (3), (5)</p>', '<p>(1), (4), (5), (3), (4)</p>', 'B', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(42, 15, 20, '<p>Perhatikan pernyataan berikut :</p>\r\n<ol style=\"list-style-type: upper-alpha;\">\r\n<li>Memberikan materi pembelajaran agar mudah diserap dan dapat dimainkan ulang</li>\r\n<li>Memperkenalkan produk</li>\r\n<li>Membantu mengkomunikasikan gagasan atau konsep melalui video sebagai media Dengar pandang</li>\r\n<li>Menunjukan cara kerja</li>\r\n<li>Merekam sebuah kejadian atau peristiwa dalam kehidupan nyata</li>\r\n</ol>\r\n<p>Dari pernyataan diatas, manakah yang bukan termasuk tujuan presentasi video?</p>', 1, '<p>(A), (B)</p>', '<p>(B), (C)</p>', '<p>(C), (D)</p>', '<p>(D), (E)</p>', '<p>(E), (A)</p>', 'E', '', '', '', '', '', '', ''),
(43, 15, 21, '<p>Dido mempunyai file presentasi yang sudah lengkap dengan animasi ataupun transisi. Setelah dicek kembali, ternyata Dido kurang puas akan file tersebut dan berencana akan menambahkan efek suara.</p>\r\n<p>Bagaimana langkah-langkah yang harus dilakukan Dido?</p>', 1, '<p>Klik menu Transition &rarr; Transition to This Slide</p>', '<p>Klik menu Transition &rarr; Apply to All</p>', '<p>Klik menu Transition &rarr; Sound</p>', '<p>Klik menu Transition &rarr; Advance Slide</p>', '<p>Klik menu Transition &rarr; Duration</p>', 'C', '', '', '', '', '', '', ''),
(44, 15, 22, '<p>Perhatikan pernyataan berikut :</p>\r\n<p>(1) focus pada diskusi</p>\r\n<p>(2) periksa peralatan yang digunakan</p>\r\n<p>(3) gunakan bahasa yang baik dan sopan</p>\r\n<p>(4) tidak menggunakan jenis huruf (font) yang beragam</p>\r\n<p>(5) segena menanggapi pesan yang diterima</p>\r\n<p>Dari 5 pernyataan diatas, mana saja yang bukan termasuk tata krama komunikasi asinkron&hellip;.</p>', 1, '<p>(2), (4)</p>', '<p>(4), (5)</p>', '<p>(1), (3)</p>', '<p>(3), (4)</p>', '<p>(1), (4)</p>', 'A', '', '', '', '', '', '', ''),
(45, 15, 23, '<p>Perhatikan cerita berikut ini:</p>\r\n<p>Pada suatu hari, Anton membuka media komunikasi sosial facebook. Pertama-tama Anton membuka, membaca dan membalas setiap pesan yang masuk. Setelah selesai membalas pesan, biasanya Anton membaca postingan yang ada. Sering juga dia membagikan beberapa postingan yang dia suka. Anton tertarik terhadap satu judul postingan &ldquo;Tindakan Main Hakim Sendiri Demi Keamanan&rdquo;. Jika anda sebagai Anton, apakah yang sebaiknya anda lakukan terhadap postingan tersebut?</p>', 1, '<p>Memblokir pemilik posting.</p>', '<p>Memberikan komentar yang membangun.</p>', '<p>Menghapus postingan.</p>', '<p>Membagikan postingan.</p>', '<p>Memantau perkembangan komentar postingan tersebut.</p>', 'B', '', '', '', '', '', '', ''),
(46, 15, 24, '<p>Youtube merupakan platform sosial berbasis video yang didukung dengan musik. Salah satu yang menjadi daya tarik platform ini adalah banyak konten lucu hasil rekaman video pengguna. Berdasarkan penjelasan di atas, jenis metode transfer data pada platform ini adalah&hellip;.</p>', 1, '<p>serial</p>', '<p>buffering</p>', '<p>sinkron</p>', '<p>paralel</p>', '<p>asinkron</p>', 'B', '', '', '', '', '', '', ''),
(47, 15, 25, '<p>Perhatikan contoh komunikasi daring berikut :</p>\r\n<p>(1) Email</p>\r\n<p>(2) Text Chat</p>\r\n<p>(3) Forum</p>\r\n<p>(4) Video Chat</p>\r\n<p>(5) Video Converence</p>\r\n<p>Dari contoh komunikasi daring diatas, manakah contoh komunikasi daring asinkron?</p>', 1, '<p>(1), (3)</p>', '<p>(2), (4)</p>', '<p>(2), (3)</p>', '<p>(3), (4)</p>', '<p>(4), (5)</p>', 'A', '', '', '', '', '', '', ''),
(48, 15, 26, '<p>Kita sebagai warga digital dunia diwajibkan mengingat dan mengerti tentang akronim &ldquo;T.H.I.N.K.&rdquo; terhadap sebuah berita / postingan atau komentar disebuah komunitas daring. Yang bukan termasuk akronim &ldquo;T.H.I.N.K.&rdquo; adalah&hellip;</p>', 1, '<p>Is It Hurtful</p>', '<p>Is It True</p>', '<p>Is it Inspiring</p>', '<p>Is it Kind</p>', '<p>Is it New</p>', 'E', '', '', '', '', '', '', ''),
(49, 15, 27, '<p>Hukum digital digunakan untuk mengatur etiket penggunaan teknologi dalam masyarakat. Warga digital perlu menyadari bahwa mencuri ataupun mengubah data diri maupun karya digital orang lain merupakan perbuatan melanggar hukum. Contoh, ada seseorang yang dengan sengaja meng-copy paste suatu produk tanpa seijin pemilik. Maka orang tersebut telah melanggar hukum digital?</p>', 1, '<p>Privasi</p>', '<p>Merek dagang</p>', '<p>Fitnah dan pencemaran nama baik</p>', '<p>Hak cipta</p>', '<p>Yurisdiksi dalam ruang siber</p>', 'D', '', '', '', '', '', '', ''),
(50, 15, 28, '<p>Wawan akan mencari informasi melalui mesin pencari Google dengan kata kunci &ldquo;<strong>Menjadi * Juara</strong>&rdquo;, maka informasi apa yang akan muncul pada hasil pencarian Wawan&hellip;</p>', 1, '<p>Menjadi seorang juara</p>', '<p>Menjadi seorang pemenang</p>', '<p>Menjadi seorang juara; menjadi seorang pemenang</p>', '<p>Menjadi pemenang juara</p>', '<p>Menjadi sang juara pemenang</p>', 'C', '', '', '', '', '', '', ''),
(51, 15, 29, '<p>Perhatikan gambar berikut :<img class=\"img-responsive\" src=\"data:image/png;base64,\" alt=\"\" width=\"1086\" height=\"576\" /></p>\r\n<p>Fitur Google classroom yang digunakan untuk gabung atau Membuat kelas &nbsp;ditunjukan pada nomor?</p>', 1, '<p>1</p>', '<p>3</p>', '<p>6</p>', '<p>4</p>', '<p>5</p>', 'E', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(52, 15, 30, '<p>Perhatikan bentuk visualisasi berikut :</p>\r\n<table style=\"border-collapse: collapse; width: 100%;\" border=\"1\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p><strong>Poster</strong></p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p><strong>Media Web</strong></p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p><strong>Pamflet</strong></p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p><strong>Videotron</strong></p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p><strong>3D Still Image</strong></p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p>(1)</p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p>(2)</p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p>(3)</p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p>(4)</p>\r\n</td>\r\n<td style=\"width: 19.9761%; text-align: center;\" width=\"128\">\r\n<p>(5)</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>Dari bentuk visualisasi diatas, manakah yang bukan termasuk bentuk visualisasi statis&hellip;</p>', 1, '<p>(1), (5)</p>', '<p>(4), (3)</p>', '<p>(3), (5)</p>', '<p>(2), (4)</p>', '<p>(1), (3)</p>', 'D', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(53, 15, 31, '<p>Perhatikan gambar dibawah ini!</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/png;base64,\" alt=\"\" width=\"425\" height=\"289\" /></p>\r\n<p>Istilah gambar yang sesuai pada gambar diatas adalah&hellip;</p>', 1, '<p>Establishing Shot (ES)</p>', '<p>Extreme Long Shot (ELS)</p>', '<p>Very Long Shot (VLS)</p>', '<p>Long Shoot (LS)</p>', '<p>Full Shot (FS)</p>', 'B', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(54, 15, 32, '<p>Dion merekam sebuah aktifitas dimana pergerakan kamera pada posisi yang sama, tetapi berputar atas / bawah secara vertikal. Istilah gerakan kamera yang dilakukan oleh Dion adalah&hellip;</p>', 1, '<p>Track In</p>', '<p>Zoom in</p>', '<p>Pan / Paining</p>', '<p>Track Out</p>', '<p>Tilt / Tilting</p>', 'E', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(55, 15, 33, '<p>Perhatikan cerita berikut ini!</p>\r\n<p>Dari dalam sebuah ruangan terdengar suara ketukan pintu.</p>\r\n<p>&ldquo;Silakan masuk&rdquo; Sambung Pak Abdillah dari dalam ruangan.</p>\r\n<p>&ldquo;Maaf pak, apakah Pak Abdillah ada?&rdquo; Tanya seseorang yang sedang dipanggil interview.</p>\r\n<p>&ldquo;Tidak ada, silakan keluar!&rdquo;</p>\r\n<p>Selanjutnya&hellip;</p>\r\n<p>&ldquo;Maaf pak&rdquo;</p>\r\n<p>&ldquo;Tau di mana Pak Abdillah? Kenapa Office Boy (OB) yang ada di dalam ruangan?&rdquo; Tanya seseorang itu kepada karyawan lain yang berada di luar ruangan.</p>\r\n<p>&ldquo;Yang di dalam tadi Pak Abdillah. Dia memang suka pura-pura seperti itu untuk mengetes bawahannya.&rdquo; Ia menjelaskan.</p>\r\n<p>&ldquo;Maksudnya pak?&rdquo;</p>\r\n<p>&ldquo;Ya artinya kamu tidak lolos interview hari ini, begitulah Pak Abdillah. Dia trauma dengan beberapa bawahannya karena urusan materi.&rdquo;</p>\r\n<p>Dari cerita di atas merupakan contoh&hellip;.</p>', 1, '<p>storyboard</p>', '<p>naskah</p>', '<p>komik</p>', '<p>sinopsis</p>', '<p>cerpen</p>', 'E', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(56, 15, 34, '<p>Salah satu hal yang harus diperhatikan dalam pengambilan gambar adalah tata cahaya. Jika dalam pengambilan gambar dengan memanfaatkan sumber cahaya dibelakang objek, maka teknik yang digunakan adalah?</p>', 1, '<p>Three point lighting</p>', '<p>Two point lighting</p>', '<p>Key light</p>', '<p>Back light</p>', '<p>Fill light</p>', 'D', '', '', '', '', '', '', ''),
(57, 15, 35, '<p>Setelah Anton memproduksi video, tahapan berikutnya adalah melakukan kegiatan pasca produksi video dengan memberikan transisi yang berfungsi untuk menggantikan sebuah gambar terang secara berangsurangsur menjadi gelap. Teknik yang digunakan Anton adalah&hellip;</p>', 1, '<p>Fade</p>', '<p>Wipe</p>', '<p>Fading</p>', '<p>Cut / Cut To</p>', '<p>Dissolve</p>', 'C', '', '', '', '', '', '', ''),
(58, 15, 36, '<p>Berdasarkan gambar disamping,&nbsp;<img class=\"img-responsive\" src=\"data:image/png;base64,\" alt=\"\" width=\"381\" height=\"221\" /></p>\r\n<p>apabila Toni akan mengatur objek berada dibelakang teks maka Langkah yang tepat dilakukan oleh Toni adalah....</p>', 1, '<p>Klik kanan objek &rarr; Wrap Text &rarr; Square</p>', '<p>Klik kanan objek &rarr; Wrap Text &rarr; Tight</p>', '<p>Klik kanan objek &rarr; Wrap Text &rarr; Behind Text</p>', '<p>Klik kanan objek &rarr; Wrap Text &rarr; In Front of Text</p>', '<p>Klik kanan objek &rarr; Wrap Text &rarr; Throught</p>', 'C', '', '', '', '', '', '', ''),
(59, 15, 37, '<p>Perhatikan pernyataan berikut ini :</p>\r\n<p>1 Interface yang user friendly dan tidak tertata rapi.</p>\r\n<p>2 File berukuran besar.</p>\r\n<p>3 Software free (gratis)</p>\r\n<p>4 Tool untuk membuat objek 3D yang lengkap.</p>\r\n<p>5 Tidak mendukung semua platform.</p>\r\n<p>6 Kualitas arsitektur 3D yang berkualitas tinggi dan bisa dikerjakan dengan lebih cepat dan efisien.</p>\r\n<p>7 Dukungan yang aktif melalui forum dan komunitas</p>\r\n<p>Pernyataan yang tidak sesuai dengan keunggulan 3D blender ditunjukkan pada nomor&hellip;.</p>', 1, '<p>(1), (2), (3)</p>', '<p>(1), (2), (4)</p>', '<p>(1), (2), (6)</p>', '<p>(1), (2), (5)</p>', '<p>(1), (2), (7)</p>', 'D', '', '', '', '', '', '', ''),
(60, 15, 38, '<p>Perhatikan gambar dibawah ini :</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/png;base64,\" alt=\"\" width=\"741\" height=\"390\" /></p>\r\n<p>Dari gambar diatas, objek manakah yang merupakan jendela kerja dan tempat melakukan editing video&hellip;</p>', 1, '<p>Preview Pane</p>', '<p>Story Pane</p>', '<p>Ribbon</p>', '<p>Play</p>', '<p>Zoom bar</p>', 'B', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(61, 15, 39, '<p>Perhatikan aplikasi berikut :</p>\r\n<p>(1) 3DsMax</p>\r\n<p>(2) Cinema 4D</p>\r\n<p>(3) Maya</p>\r\n<p>(4) Blender</p>\r\n<p>(5) Format Factory</p>\r\n<p>(6) Any Video Converter</p>\r\n<p>Dari aplikasi diatas, manakah yang tidak termasuk aplikasi pengolah animasi 3D&hellip;</p>', 1, '<p>(5), (6)</p>', '<p>(2), (3)</p>', '<p>(3), (4)</p>', '<p>(4), (5)</p>', '<p>(1), (2)</p>', 'A', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(62, 15, 40, '<p>Perhatikan gambar dibawah ini:</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/png;base64,\" alt=\"\" width=\"320\" height=\"254\" /></p>\r\n<p>Jika Witan ingin menghaluskan setiap sudut pada gambar diatas yang awalnya runcing, maka teknik yang harus dilakukan oleh Witan menggunakan teknik?&hellip;</p>', 1, '<p>Bevel</p>', '<p>Subdivision Surface</p>', '<p>Basic Modeling</p>', '<p>Solidity Text</p>', '<p>Modifier</p>', 'A', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(63, 15, 1, '<p>Perhatikan gambar berikut!</p>\r\n<p><img class=\"img-responsive\" src=\"data:image/png;base64,\" alt=\"\" width=\"886\" height=\"497\" /></p>\r\n<p>Dari gambar Diatas, jika Hani akan mencari informasi dengan kata kunci &ldquo;Download Google Chrome&rdquo;, Hani mengetikan kata kunci tersebut dimasukan pada nomor berapa? Rincikan juga fungsi setiap nomor yang ada!</p>', 2, '', '', '', '', '', '', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(64, 15, 2, '<p>Terdapat sebuah peraturan di sebuah sekolah yang menyebutkan bahwa seluruh Peserta Didik dilarang membawa alat komunikasi berupa Handphone. Namun ada Mata Pelajaran tertentu yang memerlukan HP sebagai media pembelajaran. Andi sebagai salah satu Peserta Didik yang membawa HP tersebut namun Andi menggunakan HP tersebut untuk keperluan pribadi, bukan untuk aktifitas pembelajaran. Jika kamu adalah teman dekat Andi, uraikan empat sikap yang seharusnya kamu lakukan yang sesuai dengan kewargaan digital!</p>', 2, '', '', '', '', '', '', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(65, 15, 3, '<p>Ita akan mengirimkan email dengan menyisipkan sebuah file laporan kegiatan ekstrakurikuler pramuka kepada Pembina, rincikan langkah-langkah yang harus Ita lakukan!</p>', 2, '', '', '', '', '', '', '', '', '', '', '', '', '');
INSERT INTO `soal` (`id_soal`, `id_mapel`, `nomor`, `soal`, `jenis`, `pilA`, `pilB`, `pilC`, `pilD`, `pilE`, `jawaban`, `file`, `file1`, `fileA`, `fileB`, `fileC`, `fileD`, `fileE`) VALUES
(66, 15, 4, '<p>Tito mempunyai sebuah channel video di youtube, untuk meningkatkan trafik video tersebut Tito membagikan video tersebut ke sebuah blog. Rincikan langkah-langkah yang harus Tito lakukan!</p>', 2, '', '', '', '', '', '', '', '', '', '', '', '', ''),
(67, 15, 5, '<p>Di internet, reputasi dapat dibangun berdasarkan informasi yang dibagikan melalui blog, komentar, media sosial, foto, video, atau tautan. Seseorang akan menilai baik atau tidak baik dan akan berkontribusi membangun reputasi tersebut berdasarkan aktifitas tersebut. Rincikan masing-masing 4 contoh yang membuat repusati seseorang dinilai baik dan tidak baik!</p>', 2, '', '', '', '', '', '', '', '', '', '', '', '', ''),
(68, 9, 31, '<p>Tujuan pernikahan sering diungkapkan dengan istilah sakinah, mawadah, dan rahmah. Maksud dari sakinah ialah &hellip;.</p>', 1, '<p>cinta kasih</p>', '<p>kasih sayang</p>', '<p>persaudaraan</p>', '<p>ketenangan hidup lahir batin</p>', '<p>kekeluargaan</p>', 'D', '', '', '', '', '', '', ''),
(69, 9, 30, '<p>Rasulullah saw. bersabda bahwa nikah itu termasuk sunah, barang siapa tidak melaksanakan sunahku maka &hellip;.</p>', 1, '<p>tidak akan mendapat keturunan yang sah</p>', '<p>tidak mendapat kebahagiaan yang sah</p>', '<p>tidak akan mendapat syafaat (pertolongan) diriku</p>', '<p>tidak termasuk golonganku</p>', '<p>tidak tepat amalnya</p>', 'D', '', '', '', '', '', '', ''),
(70, 9, 29, '<p>Untuk menikah, berdasarkan anutan agama Islam calon suami harus memenuhi syarat-syarat tertentu, di antaranya ialah &hellip;.</p>', 1, '<p>bukan mahramnya</p>', '<p>tidak cacat jasmaninya</p>', '<p>kehendak calon istri</p>', '<p>mempunyai harta yang banyak</p>', '<p>belum punya istri</p>', 'A', '', '', '', '', '', '', ''),
(71, 9, 28, '<p>Hal-hal berikut ini merupakan rukun dalam pelaksanaan pernikahan, kecuali</p>', 1, '<p>ada wali calon istri</p>', '<p>ada wali calon suami</p>', '<p>ada saksi yang adil</p>', '<p>ada ijab qabul</p>', '<p>ada mempelai pria dan wanita</p>', 'B', '', '', '', '', '', '', ''),
(72, 9, 27, '<p>Jika calon sitri, tidak punya ayah, maka yang paling berhak menjadi wali ialah &hellip;.</p>', 1, '<p>ayah tiri</p>', '<p>paman dari ayah</p>', '<p>kakek dari ayah</p>', '<p>kakek dari ibu</p>', '<p>saudara laki-laki</p>', 'C', '', '', '', '', '', '', ''),
(73, 9, 26, '<p>Pejabat yang ditunjuk/diberi hak untuk menjadi wali dalam ijab kabul lantaran keadaan dan sebab-sebab tertentu disebut &hellip;.</p>', 1, '<p>wali nasab</p>', '<p>wali hakim</p>', '<p>wali aqrab</p>', '<p>wali maula</p>', '<p>wali tahkim</p>', 'B', '', '', '', '', '', '', ''),
(74, 9, 25, '<p>Pemberian yang wajib diberikan oleh calon suami kepada calon istri, namun tidak termasuk rukun nikah disebut &hellip;.</p>', 1, '<p>sedekah</p>', '<p>iwad</p>', '<p>nafkah</p>', '<p>mahar</p>', '<p>hadiah</p>', 'D', '', '', '', '', '', '', ''),
(75, 9, 24, '<p>Istri yang suaminya meninggal dunia, maka iddahnya selama &hellip;. dan sehabis itu boleh menikah lagi.</p>', 1, '<p>4 bulan 10 hari</p>', '<p>3 bulan</p>', '<p>tidak memiliki iddah</p>', '<p>7 bulan</p>', '<p>3 kali suci</p>', 'A', '', '', '', '', '', '', ''),
(76, 9, 23, '<p>Talak yang dijatuhkan oleh suami atas seruan istri dan istri menawarkan sesuatu barang kepada mantan suaminya. Talak semacam ini dinamakan &hellip;.</p>', 1, '<p>fasakh</p>', '<p>talak</p>', '<p>rujuk</p>', '<p>khuluk</p>', '<p>bain</p>', 'D', '', '', '', '', '', '', ''),
(77, 9, 22, '<p>Pernyataan berikut ini yang&nbsp; tidak sempurna ialah &hellip;.</p>', 1, '<p>kewajiban istri ialah haknya suami</p>', '<p>kewajiban suami ialah hak istri</p>', '<p>menikah tanpa wali tidak sah</p>', '<p>wali mujbir sanggup memaksa anaknya untuk menikah</p>', '<p>menikah tanpa mahar tidak sah</p>', 'D', '', '', '', '', '', '', ''),
(78, 9, 21, '<p>Hal-hal berikut yang tidak sanggup menjadi penyebab putusnya tali ijab kabul ialah &hellip;.</p>', 1, '<p>berbeda agama dan kepercayaan</p>', '<p>salah satu pihak berbuat nusyuz</p>', '<p>berbeda adat istiadat</p>', '<p>beda pendapat terus-menerus</p>', '<p>suami istri saling menuduh berzina</p>', 'C', '', '', '', '', '', '', ''),
(79, 9, 20, '<p>Perhatikan potongan ayat&nbsp;QS. Ali Imran ayat 190&nbsp;di bawah ini:<br /><span style=\"font-size: 18pt;\">&nbsp;ÙÙØ§Ø®ÙØªÙÙÙØ§ÙÙ Ø§ÙÙÙÙÙÙ ÙÙØ§ÙÙÙÙÙÙØ§Ø±Ù</span></p>\r\n<p>Potongan ayat di atas artinya . . . .</p>', 1, '<p>penciptaan langit dan bumi</p>', '<p>tanda-tanda kebesaran Allah Swt.</p>', '<p>dan pergantian malam dan siang</p>', '<p>orang-orang yang mengingat Allah Swt.</p>', '<p>dalam keadaan berdiri dan duduk</p>', 'C', '', '', '', '', '', '', ''),
(80, 9, 19, '<p>Berfikir kritis adalah Proses mental untuk menganalisis atau mengevaluasi informasi. Untuk memahami informasi secara mendalam dapat membentuk sebuah keyakinan kebenaran informasi yang didapat atau pendapat yang disampaikan, definisi tersebut adalah pendapat &hellip;..</p>', 1, '<p>Menurut Scriven &amp; Paul</p>', '<p>Menurut Jensen</p>', '<p>Menurut Mertes&nbsp;&nbsp;</p>', '<p>Menurut Ennis</p>', '<p>Menurut secara umum</p>', 'E', '', '', '', '', '', '', ''),
(81, 9, 18, '<p>Untuk menguji suatu pendapat atau ide, termasuk di dalamnya melakukan pertimbangan atau pemikiran yang didasarkan pada pendapat yang diajukan. Pertimbangan-pertimbangan tersebut biasanya didukung oleh kriteria yang dapat dipertanggungjawabkan. Merupakan&hellip;</p>', 1, '<p>Alasan berfikir kritis</p>', '<p>Tujuan berpikir kritis</p>', '<p>Manfaat berfikir kritis</p>', '<p>Argumen berfikir kritis</p>', '<p>Pentingnya berfikir kritis&nbsp;</p>', 'B', '', '', '', '', '', '', ''),
(82, 9, 17, '<p>Artinya:Dari Abu Ya&rsquo;la yaitu Syaddad Ibnu Aus r.a. dari Nabi saw. Beliau bersabda: &ldquo;Orang yang cerdas ialah orang yang mampu mengintrospeksi dirinya dan suka beramal untuk kehidupannya setelah mati. Sedangkan orang yang lemah ialah orang yang selalu &hellip;&hellip;&hellip;&hellip; dan berharap kepada Allah dengan harapan kosong&rdquo;. (HR. At-Tirmizi dan beliau berkata: Hadis Hasan), kalimat yang tepat untuk mengisi titik pada hadist tersebut adalah..</p>', 1, '<p>Malas beribadah</p>', '<p>Banyak berbuat dosa</p>', '<p>Melalikan ibadahnya</p>', '<p>Mengikuti&nbsp;&nbsp;hawa&nbsp;&nbsp;nafsunya</p>', '<p>Ingin hidup enak</p>', 'D', '', '', '', '', '', '', ''),
(83, 9, 16, '<p><span style=\"color: #000000;\">Perhatikan beberapa pernyataan berikut!</span></p>\r\n<p><span style=\"color: #000000;\">(1) Menyalati&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a></span><br /><span style=\"color: #000000;\">(2) Mengubur&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a></span><br /><span style=\"color: #000000;\">(3) Mengkafani&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a></span><br /><span style=\"color: #000000;\">(4) Memandikan&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a></span></p>\r\n<p><br /><span style=\"color: #000000;\">Urutan pengurusan&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a>&nbsp;yang tepat yaitu...</span></p>', 1, '<p>1, 4, 3, dan 2</p>', '<p>3, 1, 4, dan 2</p>', '<p>4, 1, 3, dan 2</p>', '<p>4, 3, 1, dan 2</p>', '<p>4, 3, 2, dan 1</p>', 'D', '', '', '', '', '', '', ''),
(84, 9, 15, '<p><span style=\"color: #000000;\">Perhatikan tata cara sholat&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a>&nbsp;berikut!</span><br /><span style=\"color: #000000;\">(1) Niat melaksanakan sholat&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a></span><br /><span style=\"color: #000000;\">(2) Takbir kemudian membaca sholawat Nabi</span><br /><span style=\"color: #000000;\">(3) Takbir kemudian membaca doa untuk&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a>&nbsp;dan untuk diri sendiri</span><br /><span style=\"color: #000000;\">(4) Takbir kemudian membaca surat Al Fatihah</span><br /><span style=\"color: #000000;\">(5) Takbir kemudian membaca doa untuk&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a></span></p>\r\n<p><span style=\"color: #000000;\">Urutan tata cara menyalati&nbsp;<a style=\"color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a>&nbsp;yang tepat adalah...</span></p>', 1, '<p>1 - 2 - 5 - 3 - 4</p>', '<p>1 - 2 - 4 - 5 - 3</p>', '<p>1 - 4 - 2 - 5 - 3</p>', '<p>4 - 1 - 2 - 5 - 3</p>', '<p>4 - 2 - 5 - 3 - 1</p>', 'C', '', '', '', '', '', '', ''),
(85, 9, 14, '<p><span style=\"background-color: #ffffff; color: #000000;\">Perhatikan keterangan berikut!</span><br /><span style=\"background-color: #ffffff; color: #000000;\">(1) Meminta keluarga duka untuk menyiapkan makanan</span><br /><span style=\"background-color: #ffffff; color: #000000;\">(2) Mengucapkan bela sungkawa kepada keluarga yang ditinggalkan</span><br /><span style=\"background-color: #ffffff; color: #000000;\">(3) Membantu menyiapkan keperluan bagi keluarga yang ditinggalkan</span><br /><span style=\"background-color: #ffffff; color: #000000;\">(4) Mendoakan&nbsp;<a style=\"background-color: #ffffff; color: #000000;\" href=\"https://ringtimesbali.pikiran-rakyat.com/tag/jenazah\">jenazah</a>&nbsp;agar diampuni Allah</span><br /><span style=\"background-color: #ffffff; color: #000000;\">(5) Menghibur dan mengajak keluarga almarhum tertawa terbahak-bahak</span></p>\r\n<p><span style=\"background-color: #ffffff; color: #000000;\">Tindakan yang dianjurkan saat bertakziah ditunjukkan oleh angka ...</span></p>', 1, '<p>1, 2, dan 3</p>', '<p>1, 3, dan 5</p>', '<p>2, 3, dan 4</p>', '<p>2, 4, dan 5</p>', '<p>&nbsp;3, 4, dan 5</p>', 'C', '', '', '', '', '', '', ''),
(86, 9, 13, '<p>Sebaiknya, jumlah kain kafan yang dipakai untuk membungkus mayat wanita adalah&hellip;.</p>', 1, '<p>2 lembar</p>', '<p>3 lembar</p>', '<p>4 lembar</p>', '<p>5 lembar</p>', '<p>7 lembar</p>', 'D', '', '', '', '', '', '', ''),
(87, 9, 12, '<p><img src=\"https://1.bp.blogspot.com/-Ju0juZtcV1A/WwcIOeshHiI/AAAAAAAACdw/u9IrwYH5QqYQi1g5yVzaG4PCuQoLmPcJACLcBGAs/s1600/15-4.png\" /></p>\r\n<p>Kalimat di atas dibaca ketika&hellip;.</p>', 1, '<p>hendak memandikan mayat</p>', '<p>salat mayat pada takbir kedua</p>', '<p>hendak mengkafani mayat</p>', '<p>akan memberangkatkan mayat ke kubur</p>', '<p>menurunkan mayat ke liang kubur</p>', 'E', '', '', '', '', '', '', ''),
(88, 9, 11, '<p>Salah satu hal yang disunahkan dalam mengubur mayat ialah meninggikan tanah dengan tujuan&hellip;.</p>', 1, '<p>kebanyakan tanah</p>', '<p>biar tidak diinjak-injak orang</p>', '<p>biar tidak digali hewan buas</p>', '<p>menghormati yang meninggal</p>', '<p>membedakan bahwa itu ialah kuburan</p>', 'E', '', '', '', '', '', '', ''),
(89, 9, 10, '<p>Perhatikan pernyataan-pernyataan berikut ini!</p>\r\n<p>1. Meninggalkan perbuatan yang haram dan kurang bermanfaat.<br />2. Tidak mau mencar ilmu dari pengalaman diri dan orang lain.<br />3. Melaksanakan tugas-tugas sesuai dengan jadwal yang telah ditentukan.<br />4. Bersegera dalam melaksanakan kebaikan dan meninggalkan kemaksiatan.<br />5. Menunda-nunda pekerjaan dan gemar menonton televisi.</p>\r\n<p>Dari pernyataan di atas, yang termasuk sikap kompetisi dalam kebaikan adalah&hellip;.</p>', 1, '<p>1, 3, dan 4</p>', '<p>1, 4, dan 5</p>', '<p>2, 4, dan 5</p>', '<p>2, 3, dan 4</p>', '<p>1, 2, dan 5</p>', 'A', '', '', '', '', '', '', ''),
