(165, 7, 3, '<p>Hasil reaksi untuk&nbsp; elektrolisis pada larutan <span style=\"font-family: \'times new roman\', times, serif;\"><span style=\"font-size: 14pt;\"><em><strong>Na<sub>2</sub>SO<sub>4</sub></strong></em></span>&nbsp;</span>dengan elektrode Pt adalah...&nbsp;</p>', 1, '<p><img src=\"data:image/png;base64,\" /></p>', '<p><img src=\"data:image/png;base64,\" /></p>', '<p><img src=\"data:image/png;base64,\" /></p>', '<p><img src=\"data:image/png;base64,\" /></p>', '<p><img src=\"data:image/png;base64,\" /></p>', 'D', '', '', '', '', '', '', '');
