(263, 7, 40, '<p>Berikut ini beberapa peristiwa dalam kehidupan sehari-hari.</p>\r\n<ol>\r\n<li>Hujan yang terbentuk dari uap air</li>\r\n<li>Es mencair</li>\r\n<li>Fotosintesis</li>\r\n<li>Air membeku</li>\r\n<li>Batu kapur dilarutkan dalam air</li>\r\n</ol>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Pasangan peristiwa yang menunjukkan reaksi endoterm adalah ....</p>', 1, '<p>(1) dan (2)</p>', '<p>(1) dan (4)</p>', '<p>(2) dan (3)</p>', '<p>(3) dan (4)</p>', '<p>(3) dan (5)</p>', 'B', '', '', '', '', '', '', '');
